import React, { useLayoutEffect, useState } from "react";
import GraphContainer from "../graphContainer";
import { Table } from "semantic-ui-react";
import { useConsumedSparePartsTableHooks } from "./consumed-spare-parts-table-hooks";

const ConsumedSparePartsTable = () => {
  const consumedSpareParts = useConsumedSparePartsTableHooks();
  return (
    <GraphContainer title="Top 5 Consumed Spare Parts">
      <Table>
        <Table.Header>
          <Table.Row>
            <Table.HeaderCell>Spare Part</Table.HeaderCell>
            <Table.HeaderCell>Consumed(Qty)</Table.HeaderCell>
            <Table.HeaderCell>Model</Table.HeaderCell>
            <Table.HeaderCell>Brand</Table.HeaderCell>
            <Table.HeaderCell>Code</Table.HeaderCell>
          </Table.Row>
        </Table.Header>
        <Table.Body>
          {consumedSpareParts.map((part) => (
            <Table.Row key={part.id}>
              <Table.Cell>{part.description}</Table.Cell>
              <Table.Cell>{part.quantity}</Table.Cell>
              <Table.Cell>{part.model}</Table.Cell>
              <Table.Cell>{part.brand}</Table.Cell>
              <Table.Cell>{part.code}</Table.Cell>
            </Table.Row>
          ))}
        </Table.Body>
      </Table>
    </GraphContainer>
  );
};

export default ConsumedSparePartsTable;
